Simple C++ backtracking solution:

#include<bits/stdc++.h>

using namespace std;

char expr[] = {'+','-','*','/'};

void printexpr(string str, string res, int ind, int n){
	if(ind==n){
		printf("%s\n",res.c_str());
	}else{
		printexpr(str, res+str[ind], ind+1, n);
		for(int i=0;i<4;i++){
			if(ind!=0)
				printexpr(str, res+expr[i]+str[ind], ind+1, n);
		}
	}
}

int main(){
	string str = "3481";
	printexpr(str, "", 0, str.length());
	return 0;
}
